fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let s0 = required_f32(params, "s0").map_err(anyhow::Error::msg)?;
    let s2 = required_f32(params, "s2").map_err(anyhow::Error::msg)?;
    let s3 = required_f32(params, "s3").map_err(anyhow::Error::msg)?;
    let s4 = required_f32(params, "s4").map_err(anyhow::Error::msg)?;
    let s5 = required_f32(params, "s5").map_err(anyhow::Error::msg)?;
    let s6 = required_f32(params, "s6").map_err(anyhow::Error::msg)?;
    let s7 = required_f32(params, "s7").map_err(anyhow::Error::msg)?;
    let s8 = required_f32(params, "s8").map_err(anyhow::Error::msg)?;
    let wetdry = required_f32(params, "wetdry").map_err(anyhow::Error::msg)?;
    let tempo = required_f32(params, "tempo").map_err(anyhow::Error::msg)?;
    let q = required_f32(params, "q").map_err(anyhow::Error::msg)?;
    let amp = required_bool(params, "amp").map_err(anyhow::Error::msg)?;
    let lag = required_f32(params, "lag").map_err(anyhow::Error::msg)?;
    let mode = required_f32(params, "mode").map_err(anyhow::Error::msg)?;
    let range = required_f32(params, "range").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_S0, s0),
        (PORT_CTRL_S2, s2),
        (PORT_CTRL_S3, s3),
        (PORT_CTRL_S4, s4),
        (PORT_CTRL_S5, s5),
        (PORT_CTRL_S6, s6),
        (PORT_CTRL_S7, s7),
        (PORT_CTRL_S8, s8),
        (PORT_CTRL_WETDRY, wetdry),
        (PORT_CTRL_TEMPO, tempo),
        (PORT_CTRL_Q, q),
        (PORT_CTRL_AMP, if amp { 1.0 } else { 0.0 }),
        (PORT_CTRL_LAG, lag),
        (PORT_CTRL_MODE, mode),
        (PORT_CTRL_RANGE, range),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_INPUT_L, PORT_AUDIO_IN_INPUT_R], &[PORT_AUDIO_OUT_OUTPUT_L, PORT_AUDIO_OUT_OUTPUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

